#include <stdio.h>
#define MAX_R 10
#define MAX_C 1000000

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int R, C;
        double p;
        scanf("%d %d %lf", &R, &C, &p);
        double dp[R][C];
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                if (i == R - 1 && j == C - 1) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = 0;
                }
            }
        }
        for (int i = R - 2; i >= 0; i--) {
            for (int j = C - 2; j >= 0; j--) {
                double prob = 0;
                if (i + 1 < R) prob += (1 - p) * dp[i + 1][j];
                if (j + 1 < C) prob += (1 - p) * dp[i][j + 1];
                dp[i][j] = prob;
            }
        }
        printf("%.10f\n", dp[0][0]);
    }
    return 0;
}

